import java.text.*;
import java.nio.file.Files;
import java.nio.file.Paths;

i = 0
def groovyUtils = new com.eviware.soapui.support.GroovyUtils(context)
def projectPath = groovyUtils.projectPath
def ProjectName= testRunner.testCase.testSuite.project.getName();


SimpleDateFormat sdfDate = new SimpleDateFormat("yyyy_MM_dd_HH_mm_ss");
Date now = new Date();
String dateString = sdfDate.format(now);
testRunner.testCase.testSuite.project.setPropertyValue( "dateString", dateString)

testSuiteName = testRunner.testCase.testSuite.getName()
log.info projectPath + "/" + ProjectName + "/" + testSuiteName + "/" + dateString + "/"
String execLogsDirPath = projectPath + "/" + ProjectName + "/" + testSuiteName + "/" + dateString + "/"
File dir=new File(execLogsDirPath);
dir.mkdirs();
testRunner.testCase.testSuite.testCaseList.each {
   eachtestCase = it
   testCaseName = eachtestCase.getName()
   log.info "Test Case : ${eachtestCase.name}"
   it.testStepList.each {
   	eachteststep = it
   	tstype = eachteststep.config.type
	if (tstype == "restrequest" && (eachtestCase.disabled != true) && (eachteststep.disabled != true))
	{
	testStepName = eachteststep.getName()
	i = i + 1
	def myfile = new File( execLogsDirPath + "${i} - ${testCaseName}-${testStepName}.json" )
	myfile.append("\n-----------------------------REQUEST-------------------------------------------------\n")
	myfile.append(new String(eachteststep.testRequest.messageExchange.rawRequestData))
	myfile.append("\n-----------------------------RESPONSE------------------------------------------------\n")
	myfile.append(new String(eachteststep.testRequest.messageExchange.rawResponseData))
	}
   }
}

